import{_ as a,o as l,c as i,ak as d}from"./chunks/framework.v1e5hYbe.js";const g=JSON.parse('{"title":"更新履歴 / Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md"}'),o={name:"guide/changelog.md"};function t(r,e,n,h,c,u){return l(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="更新履歴-changelog" tabindex="-1">更新履歴 / Changelog <a class="header-anchor" href="#更新履歴-changelog" aria-label="Permalink to &quot;更新履歴 / Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_0-6-2-2026-03-04" tabindex="-1">[0.6.2] - 2026-03-04 <a class="header-anchor" href="#_0-6-2-2026-03-04" aria-label="Permalink to &quot;[0.6.2] - 2026-03-04&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>依然として生じていた第3階層以上のデータが強制的に解体される問題を修正</li></ul><h2 id="_0-6-0-2026-03-03" tabindex="-1">[0.6.0] - 2026-03-03 <a class="header-anchor" href="#_0-6-0-2026-03-03" aria-label="Permalink to &quot;[0.6.0] - 2026-03-03&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>認証システムの中核ロジックを別アセンブリおよび DLL (<code>Lyra.MenuManager.Editor.Auth</code>) へ分離</li><li><code>MenuLayoutData</code> における複数レイアウト (<code>BaseLayout</code>, <code>ExtendedLayout</code>) のサポート</li><li>認証状態の変更を通知する <code>OnAuthChanged</code> イベントによる疎結合なアーキテクチャの導入</li><li>インスペクター内での永続的な Foldout 状態の保存機能</li><li><code>MenuLayoutData</code> インスペクターにオンラインマニュアルおよびサポートへのリンクを追加</li><li>保存時に第3階層以上のデータが強制的に解体される問題を修正</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>レイアウトデータの保存方法をスクリプト内データコンテナからScriptableObjectへ変更</li><li>認証ウィンドウの UI レイアウトを改善（文字の浮き、メッセージの端切れを修正）</li><li>プロジェクト全域の NDMF <code>.after</code> 実行順序設定を <code>Settings</code> ウィンドウに集約</li><li>認証アセンブリから <code>MenuManagerSettings</code> への直接参照を削除し、循環参照を回避</li><li>コンパイルエラー防止のため、メインエディターアセンブリへの依存関係を整理</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>カスタムフォルダのイタリック表示が正しく適用されない問題を修正</li><li>動的メニューや More フォルダがビルド時に正しく処理されない問題を修正</li><li>認証後の UI 再描画に関連する GUI エラーを解消</li><li>大規模なアバターでの保存処理の安定性を向上</li></ul><h2 id="_0-5-0-2026-03-02" tabindex="-1">[0.5.0] - 2026-03-02 <a class="header-anchor" href="#_0-5-0-2026-03-02" aria-label="Permalink to &quot;[0.5.0] - 2026-03-02&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>package.json を追加</li><li>他の NDMF プラグインとの実行順序を制御する <code>RunAfterPlugins</code> 機能</li><li>Assembly Definition (<code>Lyra.MenuManager</code>, <code>Lyra.MenuManager.Editor</code>) を導入</li><li>更新履歴 (<code>CHANGELOG.md</code>) を追加</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>プロジェクトのディレクトリ構造を再編成</li><li><code>MenuLayoutData</code> を <code>Scripts/</code> (Runtime) に分離</li><li>エディタースクリプトを <code>Scripts/Editor/</code> に移動</li></ul><h2 id="_0-3-0-2026-03-01" tabindex="-1">[0.3.0] - 2026-03-01 <a class="header-anchor" href="#_0-3-0-2026-03-01" aria-label="Permalink to &quot;[0.3.0] - 2026-03-01&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>メニューのリセット機能</li><li>アイコン設定機能</li><li>フォルダ用アイコン (<code>folder.png</code>) を追加</li><li>ビルド時間用アイコン (<code>upload.png</code>) を追加</li><li>超過フォルダ用アイコン (<code>overflow.png</code>) を追加</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>リセット動作の挙動を改善</li><li>Extra Optionの動作を修正</li><li>アイコン画像のサイズを最適化</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Extra Option周りの不具合を修正</li></ul><h2 id="_0-2-0-2026-03-01" tabindex="-1">[0.2.0] - 2026-03-01 <a class="header-anchor" href="#_0-2-0-2026-03-01" aria-label="Permalink to &quot;[0.2.0] - 2026-03-01&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>ビルド時のVRCSDK内エラーメッセージ表示を修正</li><li>メニューアイテムの重複問題を修正</li><li>ビルド時間関連の処理を修正</li></ul><h2 id="_0-1-0-2026-02-28" tabindex="-1">[0.1.0] - 2026-02-28 <a class="header-anchor" href="#_0-1-0-2026-02-28" aria-label="Permalink to &quot;[0.1.0] - 2026-02-28&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>αリリース</li></ul>',31)])])}const f=a(o,[["render",t]]);export{g as __pageData,f as default};
